function memoize(fn) {
  const cache = {};
  return function(...args) {
    const key = JSON.stringify(args);
    if (cache[key]) return cache[key];
    cache[key] = fn.apply(this, args);
    return cache[key];
  };
}

function proc(d, f) {
  var res = [];
  var temp = d.filter(x => x.val > f);
  for (var i = 0; i < temp.length; i++) {
    var obj = temp[i];
    res.push({ id: obj.id, v: obj.val * 1.1 });
  }
  return res;
}

